// ━━━ AI Slide Adder (inline prompt) ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
function AiSlideAdder({ item, insertIndex, onClose, dispatch, guidelines }) {
  const [prompt, setPrompt] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const inputRef = useRef(null);
  useEffect(() => { inputRef.current?.focus(); }, []);

  const generate = async () => {
    if (!prompt.trim() || loading) return;
    setLoading(true);
    setError(null);
    try {
      const prevSlide = insertIndex > 0 ? item.slides[insertIndex - 1] : null;
      const nextSlide = insertIndex < item.slides.length ? item.slides[insertIndex] : null;
      const slide = await generateAiSlide(prompt.trim(), prevSlide, nextSlide, item.title, item.notes, guidelines);
      if (slide) {
        dispatch({ type: "INSERT_SLIDE", id: item.id, index: insertIndex, slide });
        dispatch({ type: "SELECT", id: item.id });
        setTimeout(() => dispatch({ type: "SET_SLIDE_INDEX", index: insertIndex }), 0);
        onClose();
      }
    } catch (e) {
      setError(e.message || "Generation failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: "4px 8px 6px 38px", display: "flex", flexDirection: "column", gap: 4 }} onClick={(e) => e.stopPropagation()}>
      <div style={{ display: "flex", gap: 4, alignItems: "center" }}>
        <span style={{ fontSize: 10, color: T.accent, fontFamily: FONT.mono, fontWeight: 700, flexShrink: 0 }}>AI+</span>
        <input
          ref={inputRef}
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          onKeyDown={(e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); generate(); } if (e.key === "Escape") onClose(); }}
          placeholder="Describe the slide you want..."
          disabled={loading}
          style={{ ...S.input({ padding: "3px 8px", fontSize: 12, borderRadius: 4 }), opacity: loading ? 0.5 : 1 }}
        />
        <button onClick={generate} disabled={loading || !prompt.trim()}
          style={{ ...S.primaryBtn({ padding: "3px 8px", fontSize: 10, borderRadius: 4 }), opacity: (loading || !prompt.trim()) ? 0.4 : 1, cursor: (loading || !prompt.trim()) ? "not-allowed" : "pointer", minWidth: 28 }}>
          {loading ? <span style={{ display: "inline-block", animation: "spin 1s linear infinite" }}>⚡</span> : "⚡"}
        </button>
        <button onClick={onClose} style={S.cancelBtn({ padding: "3px 6px", fontSize: 10, borderRadius: 4 })}>✕</button>
      </div>
      {loading && <div style={{ fontSize: 9, fontFamily: FONT.mono, color: T.accent, paddingLeft: 28, display: "flex", alignItems: "center", gap: 4 }}>
        <span style={{ display: "inline-block", animation: "spin 1s linear infinite" }}>🔧</span> generating slide...
      </div>}
      {error && <div style={{ fontSize: 9, fontFamily: FONT.mono, color: T.red, paddingLeft: 28 }}>⚠ {error}</div>}
    </div>
  );
}



// --- Empty Module AI Slide Adder ---
function EmptyAiSlideAdder({ item, dispatch, guidelines }) {
  const [open, setOpen] = useState(false);
  if (!open) return (
    <div onClick={(e) => { e.stopPropagation(); setOpen(true); }}
      style={{ padding: "3px 8px 3px 38px", fontSize: 10, fontFamily: FONT.mono, color: T.accent, cursor: "pointer", opacity: 0.5, transition: "opacity .15s" }}
      onMouseEnter={(e) => e.currentTarget.style.opacity = 1}
      onMouseLeave={(e) => e.currentTarget.style.opacity = 0.5}
    >+ ai slide</div>
  );
  return <AiSlideAdder item={item} insertIndex={0} onClose={() => setOpen(false)} dispatch={dispatch} guidelines={guidelines} />;
}

// ━━━ Slide List with AI Adder ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
function SlideListWithAdder({ item, selected, slideIndex, dispatch, guidelines, globalMaxSlideDur, slideOffset, slideTimeOffset }) {
  const [adderAt, setAdderAt] = useState(null);
  const [dropTarget, setDropTarget] = useState(null);
  const [editingSi, setEditingSi] = useState(null);
  const [editTitle, setEditTitle] = useState("");
  const maxSlideDur = globalMaxSlideDur || 1;
  const activeSlideRef = useRef(null);
  useEffect(() => {
    if (selected && activeSlideRef.current) {
      requestAnimationFrame(() => activeSlideRef.current?.scrollIntoView({ block: "nearest", behavior: "smooth" }));
    }
  }, [slideIndex, selected]);

  const startEditSlideTitle = (e, si, currentTitle) => { e.stopPropagation(); setEditingSi(si); setEditTitle(currentTitle); };
  const commitSlideTitle = (si) => {
    const trimmed = editTitle.trim();
    if (!trimmed) { setEditingSi(null); return; }
    const slide = item.slides[si];
    const { source, blockIndex } = getSlideSource(slide, si);
    if (source === "heading" || source === "badge") {
      // Update the actual block text
      const blocks = [...(slide.blocks || [])];
      blocks[blockIndex] = { ...blocks[blockIndex], text: trimmed };
      dispatch({ type: "UPDATE_SLIDE", id: item.id, index: si, patch: { blocks }, merge: true });
    } else {
      // No heading/badge exists — prepend a heading block
      const blocks = [{ type: "heading", text: trimmed, size: "2xl" }, ...(slide.blocks || [])];
      dispatch({ type: "UPDATE_SLIDE", id: item.id, index: si, patch: { blocks }, merge: true });
    }
    // Clean up orphaned slide.title if it exists
    if (slide.title) dispatch({ type: "UPDATE_SLIDE", id: item.id, index: si, patch: { title: undefined }, merge: true });
    setEditingSi(null);
  };

  const handleSlideDragStart = (e, si) => {
    e.stopPropagation();
    e.dataTransfer.setData("application/vela-slide", JSON.stringify({ fromItemId: item.id, slideIndex: si }));
    e.dataTransfer.effectAllowed = "move";
    e.currentTarget.style.opacity = "0.35";
  };

  const handleSlideDragEnd = (e) => {
    e.currentTarget.style.opacity = "1";
    setDropTarget(null);
  };

  const handleSlideDragOver = (e, si) => {
    if (!e.dataTransfer.types.includes("application/vela-slide")) return;
    e.preventDefault();
    e.stopPropagation();
    e.dataTransfer.dropEffect = "move";
    const rect = e.currentTarget.getBoundingClientRect();
    const mid = rect.top + rect.height / 2;
    setDropTarget({ index: si, pos: e.clientY < mid ? "top" : "bottom" });
  };

  const handleSlideDrop = (e, si) => {
    if (!e.dataTransfer.types.includes("application/vela-slide")) return;
    e.preventDefault();
    e.stopPropagation();
    setDropTarget(null);
    try {
      const data = JSON.parse(e.dataTransfer.getData("application/vela-slide"));
      if (!data || data.slideIndex == null) return;
      const rect = e.currentTarget.getBoundingClientRect();
      const toIndex = e.clientY < rect.top + rect.height / 2 ? si : si + 1;
      if (data.fromItemId === item.id) {
        let from = data.slideIndex, to = toIndex;
        if (from === to || from === to - 1) return;
        if (from < to) to--;
        dispatch({ type: "REORDER_SLIDE", id: item.id, from, to });
        dispatch({ type: "SET_SLIDE_INDEX", index: to });
      } else {
        dispatch({ type: "MOVE_SLIDE_TO_MODULE", fromId: data.fromItemId, toId: item.id, index: data.slideIndex, toIndex });
      }
    } catch {}
  };

  const handleContainerDrop = (e) => {
    if (!e.dataTransfer.types.includes("application/vela-slide")) return;
    e.preventDefault();
    e.stopPropagation();
    setDropTarget(null);
    try {
      const data = JSON.parse(e.dataTransfer.getData("application/vela-slide"));
      if (!data || data.slideIndex == null) return;
      if (data.fromItemId === item.id) {
        const from = data.slideIndex, to = item.slides.length - 1;
        if (from !== to) dispatch({ type: "REORDER_SLIDE", id: item.id, from, to });
      } else {
        dispatch({ type: "MOVE_SLIDE_TO_MODULE", fromId: data.fromItemId, toId: item.id, index: data.slideIndex });
      }
    } catch {}
  };

  return (
    <div style={{ paddingLeft: 28, paddingRight: 8, paddingBottom: 4, minHeight: 8 }}
      onDragOver={(e) => { if (e.dataTransfer.types.includes("application/vela-slide")) { e.preventDefault(); e.dataTransfer.dropEffect = "move"; } }}
      onDrop={handleContainerDrop}
      onDragLeave={() => setDropTarget(null)}
    >
      {adderAt === 0 ? (
        <AiSlideAdder item={item} insertIndex={0} onClose={() => setAdderAt(null)} dispatch={dispatch} guidelines={guidelines} />
      ) : (
        <div onClick={(e) => { e.stopPropagation(); setAdderAt(0); }}
          style={{ padding: "1px 12px", fontSize: 9, fontFamily: FONT.mono, color: T.textDim, cursor: "pointer", opacity: 0, transition: "opacity .15s", textAlign: "center", lineHeight: "14px" }}
          onMouseEnter={(e) => e.currentTarget.style.opacity = 0.6}
          onMouseLeave={(e) => e.currentTarget.style.opacity = 0}
          title="AI: insert slide here"
        >+ ai</div>
      )}
      {(() => { let cumTime = slideTimeOffset || 0; return item.slides.map((s, si) => {
        const title = typeof getSlideTitle === "function" ? getSlideTitle(s, si) : `Slide ${si + 1}`;
        const isActive = selected && slideIndex === si;
        const isDragTop = dropTarget && dropTarget.index === si && dropTarget.pos === "top";
        const isDragBot = dropTarget && dropTarget.index === si && dropTarget.pos === "bottom";
        const sDur = s.duration || 0;
        const sPct = sDur > 0 ? Math.max(3, Math.round((sDur / maxSlideDur) * 100)) : 0;
        const slideCumTime = cumTime;
        cumTime += sDur;
        return <React.Fragment key={si}>
          <div
            ref={isActive ? activeSlideRef : null}
            draggable={editingSi !== si}
            onDragStart={(e) => handleSlideDragStart(e, si)}
            onDragEnd={handleSlideDragEnd}
            onDragOver={(e) => handleSlideDragOver(e, si)}
            onDragLeave={() => setDropTarget((p) => p && p.index === si ? null : p)}
            onDrop={(e) => handleSlideDrop(e, si)}
            onClick={(e) => { e.stopPropagation(); if (editingSi === si) return; if (!selected) dispatch({ type: "SELECT", id: item.id }); setTimeout(() => dispatch({ type: "SET_SLIDE_INDEX", index: si }), 0); }}
            style={{
              padding: "3px 8px 3px 12px", fontSize: 14, fontFamily: FONT.body, cursor: editingSi === si ? "text" : "grab",
              color: isActive ? T.accent : T.textMuted, fontWeight: isActive ? 600 : 400,
              borderLeft: `2px solid ${isActive ? T.accent : "transparent"}`,
              background: isActive ? T.accent + "0a" : "transparent",
              borderTop: isDragTop ? `2px solid ${T.accent}` : "2px solid transparent",
              borderBottom: isDragBot ? `2px solid ${T.accent}` : "2px solid transparent",
              borderRadius: "0 3px 3px 0", marginBottom: 1,
              display: "flex", alignItems: "center",
              overflow: "hidden", whiteSpace: "nowrap",
              transition: "background .12s, color .12s",
              position: "relative",
            }}
            onMouseEnter={(e) => { if (!isActive) e.currentTarget.style.color = T.text; e.currentTarget.style.background = T.accent + "10"; }}
            onMouseLeave={(e) => { if (!isActive) e.currentTarget.style.color = T.textMuted; e.currentTarget.style.background = isActive ? T.accent + "0a" : "transparent"; }}
          >
            {sPct > 0 && <div title={`${fmtTime(sDur)}${s.timeLock ? " 🔒" : ""}`} style={{ position: "absolute", left: 0, bottom: 0, height: 2, width: `${sPct}%`, background: "#8B5CF630", borderRadius: "0 1px 1px 0", cursor: "default" }} />}
            <span style={{ fontFamily: FONT.mono, fontSize: 9, color: isActive ? T.accent : T.textDim, marginRight: 4, fontWeight: 700, minWidth: 14 }}>{(slideOffset || 0) + si + 1}</span>
            {s.studyNotes?.text ? <span data-study-marker title="Has offline study notes" style={{ fontSize: 10, lineHeight: 1, marginRight: 3, flexShrink: 0 }}>🎓</span> : null}
            <span style={{ fontFamily: FONT.mono, fontSize: 9, color: isActive ? T.accent : T.text, marginRight: 4, minWidth: 30, textAlign: "right", display: "inline-block" }}>{((t) => { const m = Math.floor(t / 60); const s = t % 60; return (m < 10 ? "0" : "") + m + ":" + (s < 10 ? "0" : "") + s; })(slideCumTime)}</span>
            {editingSi === si ? (
              <input autoFocus value={editTitle}
                onChange={(e) => setEditTitle(e.target.value)}
                onKeyDown={(e) => { if (e.key === "Enter") commitSlideTitle(si); if (e.key === "Escape") setEditingSi(null); }}
                onBlur={() => commitSlideTitle(si)}
                onClick={(e) => e.stopPropagation()}
                style={{ ...S.input({ padding: "1px 4px", fontSize: 12, border: `1px solid ${T.accent}` }), flex: 1, minWidth: 0 }}
              />
            ) : (
              <span onDoubleClick={(e) => startEditSlideTitle(e, si, title)} style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{title}</span>
            )}
          </div>
          {adderAt === si + 1 ? (
            <AiSlideAdder item={item} insertIndex={si + 1} onClose={() => setAdderAt(null)} dispatch={dispatch} guidelines={guidelines} />
          ) : (
            <div onClick={(e) => { e.stopPropagation(); setAdderAt(si + 1); }}
              style={{ padding: "1px 12px", fontSize: 9, fontFamily: FONT.mono, color: T.textDim, cursor: "pointer", opacity: 0, transition: "opacity .15s", textAlign: "center", lineHeight: "14px" }}
              onMouseEnter={(e) => e.currentTarget.style.opacity = 0.6}
              onMouseLeave={(e) => e.currentTarget.style.opacity = 0}
              title="AI: insert slide here"
            >+ ai</div>
          )}
        </React.Fragment>;
      }); })()}
    </div>
  );
}

// ━━━ Concept Row ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
function ConceptRow({ item, selected, laneId, dispatch, maxTime, globalMaxSlideDur, slideIndex, guidelines, slideOffset, slideTimeOffset, reviewMode, isFirst, isLast }) {
  const [editing, setEditing] = useState(false);
  const [title, setTitle] = useState(item.title);
  const [dropPos, setDropPos] = useState(null); // "top" | "bottom" | null
  const [notesOpen, setNotesOpen] = useState(false);
  const [commentText, setCommentText] = useState("");
  const [collapsed, setCollapsed] = useState(false);
  const [hovered, setHovered] = useState(false);
  const startRename = (e) => { e.stopPropagation(); setEditing(true); setTitle(item.title); };
  const commitRename = () => { if (title.trim() && title.trim() !== item.title) dispatch({ type: "RENAME_ITEM", id: item.id, title: title.trim() }); setEditing(false); };

  // Section-level drag/drop on outer wrapper (works even when expanded)
  const handleSectionDragOver = (e) => {
    // Only handle section drags, let slide drags pass through
    if (!e.dataTransfer.types.includes("application/vela-section")) return;
    e.preventDefault(); e.dataTransfer.dropEffect = "move";
    const rect = e.currentTarget.getBoundingClientRect();
    const mid = rect.top + rect.height / 2;
    setDropPos(e.clientY < mid ? "top" : "bottom");
  };

  const handleSectionDrop = (e) => {
    if (!e.dataTransfer.types.includes("application/vela-section")) return;
    e.preventDefault(); e.stopPropagation(); 
    const pos = dropPos;
    setDropPos(null);
    try {
      const d = JSON.parse(e.dataTransfer.getData("application/vela-section"));
      if (d.itemId === item.id) return;
      dispatch({ type: "DRAG_REORDER", id: d.itemId, targetLaneId: laneId, beforeId: pos === "top" ? item.id : null, afterId: pos === "bottom" ? item.id : null });
    } catch {}
  };

  // Slide cross-module drops (on the header row only)
  const handleRowDragOver = (e) => {
    if (!e.dataTransfer.types.includes("application/vela-slide")) return;
    e.preventDefault(); e.dataTransfer.dropEffect = "move";
    setDropPos("slide");
  };

  const handleRowDrop = (e) => {
    if (!e.dataTransfer.types.includes("application/vela-slide")) return;
    e.preventDefault(); e.stopPropagation(); setDropPos(null);
    try {
      const sd = e.dataTransfer.getData("application/vela-slide");
      if (sd) {
        const slideData = JSON.parse(sd);
        if (slideData && slideData.slideIndex != null && slideData.fromItemId !== item.id) {
          dispatch({ type: "MOVE_SLIDE_TO_MODULE", fromId: slideData.fromItemId, toId: item.id, index: slideData.slideIndex });
        }
      }
    } catch {}
  };

  const hasNotes = !!(item.notes && item.notes.trim());
  const itemComments = item.comments || [];
  const slideComments = (item.slides || []).flatMap((s, si) => (s.comments || []).map((c) => ({ ...c, slideIndex: si })));
  const allItemComments = [...itemComments.map((c) => ({ ...c, slideIndex: null })), ...slideComments];
  const openCommentCount = allItemComments.filter((c) => c.status === "open").length;
  const hasSlides = item.slides.length > 0;
  const itemTime = item.slides.reduce((a, s) => a + (s.duration || 0), 0);
  const timePct = maxTime > 0 && itemTime > 0 ? Math.max(3, Math.round((itemTime / maxTime) * 100)) : 0;

  return (
    <div
      onDragOver={handleSectionDragOver}
      onDragLeave={(e) => { if (!e.currentTarget.contains(e.relatedTarget)) setDropPos(null); }}
      onDrop={handleSectionDrop}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        borderTop: dropPos === "top" ? `2px solid ${T.accent}` : "2px solid transparent",
        borderBottom: dropPos === "bottom" ? `2px solid ${T.accent}` : "2px solid transparent",
      }}
    >
      <div className={`concept-row ${selected ? "selected" : ""}`}
        onClick={() => dispatch({ type: "SELECT", id: item.id })}
        draggable
        onDragStart={(e) => {
          e.dataTransfer.setData("application/vela-section", JSON.stringify({ itemId: item.id, laneId }));
          e.dataTransfer.setData("text/plain", JSON.stringify({ itemId: item.id, laneId }));
          e.dataTransfer.effectAllowed = "move";
        }}
        onDragOver={handleRowDragOver}
        onDragLeave={() => { if (dropPos === "slide") setDropPos(null); }}
        onDrop={handleRowDrop}
        style={{ padding: "7px 12px 7px 10px", borderLeft: "2px solid transparent", display: "flex", alignItems: "center", gap: 8, minHeight: 34, position: "relative",
          background: dropPos === "slide" ? T.accent + "15" : undefined,
          outline: dropPos === "slide" ? `1px dashed ${T.accent}60` : "none",
        }}>
        {timePct > 0 && <div title={`${item.slides.length} slides · ${fmtTime(itemTime)}`} style={{ position: "absolute", left: 0, bottom: 0, height: 3, width: `${timePct}%`, background: T.accent + "30", borderRadius: "0 2px 2px 0", cursor: "default" }} />}
        <span onClick={(e) => { e.stopPropagation(); setCollapsed(!collapsed); }} style={{ fontSize: 10, color: T.textDim, transition: "transform .15s", transform: collapsed ? "rotate(-90deg)" : "rotate(0)", cursor: "pointer", flexShrink: 0, width: 12, textAlign: "center" }}>▼</span>
        <div className="imp-dot" onClick={(e) => { e.stopPropagation(); const cycle = { must: "should", should: "nice", nice: "must" }; dispatch({ type: "SET_IMPORTANCE", id: item.id, importance: cycle[item.importance || "should"] }); }} style={{ background: IMP[item.importance || "should"].dot, cursor: "pointer" }} title={`Priority: ${IMP[item.importance || "should"].label} (click to cycle)`} />
        {editing ? <input autoFocus value={title} onChange={(e) => setTitle(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") commitRename(); if (e.key === "Escape") setEditing(false); }} onBlur={commitRename} onClick={(e) => e.stopPropagation()} style={S.input({ padding: "2px 6px", border: `1px solid ${T.borderLight}` })} />
          : <span onDoubleClick={startRename} style={{ flex: 1, fontSize: 14, fontFamily: FONT.body, color: T.text, fontWeight: 600, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{item.title}</span>}
        {reviewMode && openCommentCount > 0 && <span style={{ fontSize: 9, fontFamily: FONT.mono, fontWeight: 700, color: "#fff", background: T.amber, borderRadius: 8, padding: "0 4px", minWidth: 14, textAlign: "center", flexShrink: 0, lineHeight: "16px" }}>{openCommentCount}</span>}
        {reviewMode && <span onClick={(e) => { e.stopPropagation(); setNotesOpen(!notesOpen); }} title={notesOpen ? "Hide comments" : "Show comments"} style={{ fontSize: 10, cursor: "pointer", flexShrink: 0, opacity: (openCommentCount > 0 || hasNotes) ? 1 : 0.3, color: (openCommentCount > 0 || hasNotes) ? T.accent : T.textDim, lineHeight: 1 }}>💬</span>}
        <span onClick={(e) => { e.stopPropagation(); dispatch({ type: "TOGGLE_PRESENT_CARD", id: item.id }); }} title={item.presentCard ? "Title card ON (click to disable)" : "Title card OFF (click to enable)"} style={{ fontSize: 10, cursor: "pointer", flexShrink: 0, opacity: item.presentCard ? 1 : 0.25, color: item.presentCard ? T.accent : T.textDim, lineHeight: 1 }}>🎬</span>
        {hovered && <span style={{ display: "flex", flexDirection: "column", gap: 0, flexShrink: 0 }}>
          <span onClick={(e) => { e.stopPropagation(); dispatch({ type: "REORDER", id: item.id, dir: "up" }); }} title="Move up" style={{ fontSize: 8, color: isFirst ? T.border : T.textDim, cursor: isFirst ? "default" : "pointer", lineHeight: 1, padding: "0 1px", opacity: isFirst ? 0.3 : 0.7 }}>▲</span>
          <span onClick={(e) => { e.stopPropagation(); dispatch({ type: "REORDER", id: item.id, dir: "down" }); }} title="Move down" style={{ fontSize: 8, color: isLast ? T.border : T.textDim, cursor: isLast ? "default" : "pointer", lineHeight: 1, padding: "0 1px", opacity: isLast ? 0.3 : 0.7 }}>▼</span>
        </span>}
        <span onClick={(e) => { e.stopPropagation(); dispatch({ type: "REMOVE_ITEM", id: item.id }); }} style={{ fontSize: 12, color: T.textDim, cursor: "pointer", padding: "0 2px", opacity: 0.3 }}>×</span>
      </div>
      {!collapsed && notesOpen && <div style={{ padding: "2px 12px 6px 38px" }} onClick={(e) => e.stopPropagation()}>
        {/* Existing comments */}
        {allItemComments.length > 0 && <div style={{ display: "flex", flexDirection: "column", gap: 2, marginBottom: 4 }}>
          {allItemComments.map((c) => (
            <div key={c.id} style={{ display: "flex", alignItems: "flex-start", gap: 4, padding: "3px 0", opacity: c.status === "resolved" ? 0.45 : 1 }}>
              <span onClick={() => {
                const payload = { itemId: item.id, commentId: c.id, slideIndex: c.slideIndex };
                dispatch({ type: c.status === "open" ? "RESOLVE_COMMENT" : "REOPEN_COMMENT", ...payload });
              }} style={{ cursor: "pointer", fontSize: 11, flexShrink: 0, lineHeight: 1, marginTop: 1 }} title={c.status === "open" ? "Resolve" : "Reopen"}>{c.status === "open" ? "○" : "●"}</span>
              <div style={{ flex: 1, minWidth: 0 }}>
                <span style={{ fontSize: 11, fontFamily: FONT.body, color: T.text, textDecoration: c.status === "resolved" ? "line-through" : "none", wordBreak: "break-word" }}>{c.text}</span>
                {c.slideIndex != null && <span style={{ fontSize: 9, fontFamily: FONT.mono, color: T.textDim, marginLeft: 4 }}>s{c.slideIndex + 1}</span>}
                {c.anchor && <span style={{ fontSize: 9, fontFamily: FONT.mono, color: T.accent, marginLeft: 4 }}>"{c.anchor}"</span>}
              </div>
              <span onClick={() => dispatch({ type: "REMOVE_COMMENT", itemId: item.id, commentId: c.id, slideIndex: c.slideIndex })} style={{ fontSize: 10, color: T.textDim, cursor: "pointer", opacity: 0.4, flexShrink: 0 }}>×</span>
            </div>
          ))}
        </div>}
        {/* Add comment input */}
        <div style={{ display: "flex", gap: 4, alignItems: "center" }}>
          <input
            value={commentText}
            onChange={(e) => setCommentText(e.target.value)}
            onKeyDown={(e) => { if (e.key === "Enter" && commentText.trim()) { dispatch({ type: "ADD_COMMENT", itemId: item.id, text: commentText.trim() }); setCommentText(""); } if (e.key === "Escape") { setCommentText(""); setNotesOpen(false); } }}
            placeholder="Add comment..."
            style={S.input({ padding: "3px 6px", fontSize: 11 })}
          />
          <button onClick={() => { if (commentText.trim()) { dispatch({ type: "ADD_COMMENT", itemId: item.id, text: commentText.trim() }); setCommentText(""); } }} disabled={!commentText.trim()} style={S.primaryBtn({ padding: "3px 6px", fontSize: 9, opacity: commentText.trim() ? 1 : 0.4 })}>+</button>
        </div>
      </div>}
      {!collapsed && item.slides.length === 0 && <EmptyAiSlideAdder item={item} dispatch={dispatch} guidelines={guidelines} />}
      {!collapsed && hasSlides && <SlideListWithAdder item={item} selected={selected} slideIndex={slideIndex} dispatch={dispatch} guidelines={guidelines} globalMaxSlideDur={globalMaxSlideDur} slideOffset={slideOffset || 0} slideTimeOffset={slideTimeOffset || 0} />}
    </div>
  );
}

// ━━━ Module List (flat — no lane headers) ━━━━━━━━━━━━━━━━━━━━━━━━━
function ModuleList({ lanes, selectedId, slideIndex, dispatch, maxModuleTime, guidelines, reviewMode }) {
  const [adding, setAdding] = useState(false);
  const [val, setVal] = useState("");
  const laneId = lanes[0]?.id;
  const allItems = lanes.flatMap((l) => [...l.items].sort((a, b) => (a.order ?? 999) - (b.order ?? 999)));
  const totalDeckTime = React.useMemo(() => allItems.reduce((s, i) => s + (i.slides || []).reduce((a, sl) => a + (sl.duration || 0), 0), 0), [allItems]);
  const globalMaxSlideDur = React.useMemo(() => { let m = 0; for (const i of allItems) for (const s of (i.slides || [])) { if ((s.duration || 0) > m) m = s.duration; } return m || 1; }, [allItems]);
  const addItem = () => { if (!val.trim() || !laneId) return; dispatch({ type: "ADD_ITEM", laneId, title: val.trim() }); setVal(""); };
  const handleDrop = (e) => { e.preventDefault(); if (!laneId) return; try { const d = JSON.parse(e.dataTransfer.getData("application/vela-section") || e.dataTransfer.getData("text/plain")); dispatch({ type: "DRAG_REORDER", id: d.itemId, targetLaneId: laneId, beforeId: null, afterId: null }); } catch {} };

  return (
    <div onDragOver={(e) => { if (e.dataTransfer.types.includes("application/vela-section")) { e.preventDefault(); e.dataTransfer.dropEffect = "move"; } }} onDrop={handleDrop}>
      {(() => { let offset = 0; let timeOffset = 0; return allItems.map((item, idx) => {
        const itemLaneId = lanes.find((l) => l.items.some((i) => i.id === item.id))?.id || laneId;
        const slideOffset = offset;
        const slideTimeOffset = timeOffset;
        offset += (item.slides?.length || 0);
        timeOffset += (item.slides || []).reduce((a, sl) => a + (sl.duration || 0), 0);
        return <ConceptRow key={item.id} item={item} selected={selectedId === item.id} slideIndex={slideIndex} laneId={itemLaneId} dispatch={dispatch} maxTime={totalDeckTime} globalMaxSlideDur={globalMaxSlideDur} guidelines={guidelines} slideOffset={slideOffset} slideTimeOffset={slideTimeOffset} reviewMode={reviewMode} isFirst={idx === 0} isLast={idx === allItems.length - 1} />;
      }); })()}
      {adding ? <div style={{ padding: "4px 12px", display: "flex", gap: 4 }}>
        <input autoFocus value={val} onChange={(e) => setVal(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") addItem(); if (e.key === "Escape") setAdding(false); }} placeholder="Section name" style={S.input()} />
        <button onClick={addItem} style={S.primaryBtn()}>Add</button>
        <button onClick={() => setAdding(false)} style={S.cancelBtn()}>✕</button>
      </div> : <div onClick={() => setAdding(true)} style={{ padding: "5px 12px", fontSize: 12, color: T.textDim, cursor: "pointer", fontFamily: FONT.mono, opacity: 0.5 }}>+ section</div>}
    </div>
  );
}

// © 2025-present Rui Quintino. Vela Slides — licensed under ELv2. See LICENSE.
// ━━━ Chat Markdown Renderer ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// ctx (optional): passes through to parseInline — used by StudentPanel to
// thread studyNotes.glossary through so [term](#key) renders as X-Ray popups.
function ChatMarkdown({ text, ctx }) {
  if (!text) return null;
  if (typeof text !== "string") return <span>{String(text)}</span>;
  const paragraphs = text.split(/\n\n+/);
  return <>{paragraphs.map((para, pi) => {
    const lines = para.split("\n");
    // Check if this paragraph is a bullet list
    const isList = lines.every((l) => /^\s*[-•●✅⚠️❌▸]/.test(l) || l.trim() === "");
    if (isList) {
      const items = lines.filter((l) => l.trim());
      return <div key={pi} style={{ display: "flex", flexDirection: "column", gap: 2, margin: "3px 0" }}>
        {items.map((item, ii) => {
          const cleaned = item.replace(/^\s*[-•●]\s*/, "").replace(/^\s*/, "");
          return <div key={ii} style={{ display: "flex", gap: 6, alignItems: "flex-start" }}>
            {!/^[✅⚠️❌▸]/.test(item.trim()) && <span style={{ color: T.accent, flexShrink: 0, fontSize: 9, marginTop: 4 }}>●</span>}
            <span>{parseInline(cleaned, ctx)}</span>
          </div>;
        })}
      </div>;
    }
    // Regular paragraph
    return <div key={pi} style={{ margin: pi > 0 ? "6px 0 0" : 0 }}>{parseInline(para, ctx)}</div>;
  })}</>;
}

// ━━━ Tool Trace Card (agentic UX) ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
const TOOL_META = {
  find_slides: { icon: "🔍", label: "Search" }, find_replace: { icon: "✏️", label: "Replace" },
  deck_stats: { icon: "📊", label: "Audit" }, batch_restyle: { icon: "🎨", label: "Restyle" },
  add_lane: { icon: "📁", label: "Lane" }, add_item: { icon: "➕", label: "Add" },
  batch_add_items: { icon: "📋", label: "Batch add" }, remove_item: { icon: "🗑", label: "Remove" },
  remove_lane: { icon: "🗑", label: "Remove lane" }, rename_item: { icon: "✏️", label: "Rename" },
  rename_lane: { icon: "✏️", label: "Rename lane" }, move_item: { icon: "↗️", label: "Move" },
  update_status: { icon: "●", label: "Status" }, set_importance: { icon: "⚡", label: "Priority" },
  set_slides: { icon: "🎬", label: "Set slides" }, add_slide: { icon: "🎬", label: "Add slide" }, edit_slide: { icon: "✏️", label: "Edit slide" },
  add_image_to_slide: { icon: "🖼", label: "Image" }, clear_all: { icon: "💥", label: "Clear" },
  set_branding: { icon: "🎨", label: "Brand" },
  list_comments: { icon: "💬", label: "Comments" },
  resolve_comment: { icon: "✅", label: "Resolve" },
};

function ToolTraceCard({ tool, dispatch }) {
  const [open, setOpen] = useState(false);
  const meta = TOOL_META[tool.name] || { icon: "🔧", label: tool.name };
  const running = tool.status === "running";
  const hasJumps = tool.jump?.length > 0;

  // Format input summary (compact)
  const inputSummary = (() => {
    if (!tool.input) return "";
    const keys = Object.keys(tool.input).filter((k) => k !== "slides" && k !== "slide");
    if (keys.length === 0) return "";
    const parts = keys.slice(0, 3).map((k) => { const v = tool.input[k]; return typeof v === "string" ? v.slice(0, 30) : typeof v === "object" ? "..." : String(v); });
    return parts.join(", ");
  })();

  return (
    <div style={{ borderRadius: 6, border: `1px solid ${running ? T.accent + "40" : T.border}`, overflow: "hidden", fontSize: 13, transition: "all 0.2s" }}>
      {/* Header — always visible */}
      <div onClick={() => !running && setOpen(!open)} style={{ padding: "5px 10px", display: "flex", alignItems: "center", gap: 6, cursor: running ? "default" : "pointer", background: running ? T.accent + "08" : open ? T.bgCard : "transparent", transition: "background 0.15s" }}
        onMouseEnter={(e) => { if (!running) e.currentTarget.style.background = T.bgCard; }}
        onMouseLeave={(e) => { if (!running && !open) e.currentTarget.style.background = "transparent"; }}>
        <span style={{ fontSize: 13, flexShrink: 0 }}>{running ? "⏳" : "✓"}</span>
        <span style={{ fontFamily: FONT.mono, fontSize: 10, fontWeight: 700, color: running ? T.accent : T.green, flexShrink: 0 }}>{meta.icon} {meta.label}</span>
        {inputSummary && !open && <span style={{ fontFamily: FONT.mono, fontSize: 9, color: T.textDim, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>{inputSummary}</span>}
        {running && <span style={{ fontSize: 9, animation: "spin 1s linear infinite", display: "inline-block", marginLeft: "auto" }}>⚡</span>}
        {!running && <span style={{ fontSize: 9, color: T.textDim, marginLeft: "auto" }}>{open ? "▾" : "▸"}</span>}
      </div>
      {/* Expanded detail */}
      {open && !running && <div style={{ padding: "6px 10px", borderTop: `1px solid ${T.border}`, background: T.bg, display: "flex", flexDirection: "column", gap: 4 }}>
        {tool.input && <div style={{ fontFamily: FONT.mono, fontSize: 9, color: T.textDim, lineHeight: 1.4, whiteSpace: "pre-wrap", maxHeight: 80, overflow: "auto" }}>
          {JSON.stringify(tool.input, (k, v) => (k === "slides" || k === "slide") ? "[slide data]" : v, 2)}
        </div>}
        {tool.result && <div style={{ fontFamily: FONT.body, fontSize: 10, color: T.textMuted, lineHeight: 1.4, borderTop: `1px solid ${T.border}`, paddingTop: 4 }}>{tool.result}</div>}
        {hasJumps && <div style={{ display: "flex", gap: 3, flexWrap: "wrap", marginTop: 2 }}>
          {tool.jump.slice(0, 10).map((j, k) => (
            <span key={k} onClick={(e) => { e.stopPropagation(); dispatch({ type: "SELECT", id: j.itemId }); dispatch({ type: "SET_SLIDE_INDEX", index: j.slideIdx }); }}
              style={{ display: "inline-flex", alignItems: "center", gap: 3, padding: "1px 6px", borderRadius: 8, background: T.accent + "15", border: `1px solid ${T.accent}30`, cursor: "pointer", fontSize: 9, fontFamily: FONT.mono, fontWeight: 600, color: T.accent }}>
              ▶ {j.title}{j.slideIdx > 0 ? ` #${j.slideIdx + 1}` : ""}
            </span>
          ))}
        </div>}
      </div>}
    </div>
  );
}

// ━━━ Chat Panel ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
function ChatPanel({ state, dispatch, isMobile, getLayoutStats }) {
  const [input, setInput] = useState("");
  const [pendingImages, setPendingImages] = useState([]); // [{dataUrl, name}]
  const scrollRef = useRef(null);
  const textareaRef = useRef(null);
  useEffect(() => { scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight); }, [state.chatMessages]);
  // Auto-focus input when chat panel opens
  useEffect(() => { setTimeout(() => textareaRef.current?.focus(), 50); }, []);

  const addImageFromDataTransfer = (dt) => {
    const items = dt?.items || dt?.files;
    if (!items) return false;
    let found = false;
    for (const item of items) {
      const file = item.getAsFile ? item.getAsFile() : item;
      if (file && file.type?.startsWith("image/")) {
        found = true;
        const reader = new FileReader();
        reader.onload = async () => {
          const compressed = await compressSlideImage(reader.result);
          setPendingImages((prev) => [...prev, { dataUrl: compressed, name: file.name || "image" }]);
        };
        reader.readAsDataURL(file);
      }
    }
    return found;
  };

  const handlePaste = (e) => { if (addImageFromDataTransfer(e.clipboardData)) e.preventDefault(); };
  const handleDrop = (e) => { e.preventDefault(); addImageFromDataTransfer(e.dataTransfer); };
  const removeImage = (idx) => setPendingImages((prev) => prev.filter((_, i) => i !== idx));

  const send = async (directMsg) => {
    const msg = directMsg || input.trim();
    if ((!msg && pendingImages.length === 0) || state.chatLoading) return;
    const images = directMsg ? [] : [...pendingImages];
    if (!directMsg) { setInput(""); setPendingImages([]); }
    dispatch({ type: "ADD_MSG", role: "user", content: msg || "🖼️", images: images.map((i) => i.dataUrl) });
    dispatch({ type: "SET_LOADING", value: true });
    // Add a placeholder assistant message that will accumulate tool traces
    dispatch({ type: "ADD_MSG", role: "assistant", content: "", tools: [], _streaming: true });
    const onUpdate = (lanes, debug) => {
      dispatch({ type: "LOAD_LANES", lanes });
      dispatch({ type: "SET_DEBUG", text: debug });
    };
    const onToolCall = (evt) => {
      dispatch({ type: "STREAM_TOOL", event: evt });
      // Auto-navigate when a tool completes with a jump
      if (evt.type === "done" && evt.jump?.length > 0) {
        const j = evt.jump[0];
        dispatch({ type: "SELECT", id: j.itemId });
        dispatch({ type: "SET_SLIDE_INDEX", index: j.slideIdx ?? 0 });
      }
    };
    const layoutStats = getLayoutStats?.() || null;
    const result = await callVera(msg || "Here are the images I'm attaching.", state.lanes, state.selectedId, state.slideIndex, onUpdate, images, state.branding, state.guidelines, onToolCall, state.chatMessages, layoutStats);
    // Finalize the streaming message: set content + jumps, remove _streaming flag
    dispatch({ type: "FINALIZE_STREAM", content: result.message, jumps: result.jumps });
    // Auto-navigate to the first changed/created slide
    if (result.jumps?.length > 0) {
      const j = result.jumps[0];
      dispatch({ type: "SELECT", id: j.itemId });
      dispatch({ type: "SET_SLIDE_INDEX", index: j.slideIdx ?? 0 });
    }
    if (result.lanes) dispatch({ type: "LOAD_LANES", lanes: result.lanes });
    if (result.branding) dispatch({ type: "SET_BRANDING", branding: result.branding });
    dispatch({ type: "SET_DEBUG", text: result.debug || "" });
    dispatch({ type: "SET_LOADING", value: false });
    // Register late-reply handler for SSE recovery (channel timeout fallback)
    if (result._lateReplyPending) {
      window.__velaLateReply = (msg, jumps) => {
        dispatch({ type: "FINALIZE_STREAM", content: msg, jumps: jumps || [] });
        if (jumps?.length > 0) {
          dispatch({ type: "SELECT", id: jumps[0].itemId });
          dispatch({ type: "SET_SLIDE_INDEX", index: jumps[0].slideIdx ?? 0 });
        }
        dispatch({ type: "SET_DEBUG", text: "🔧 Late reply applied" });
        window.__velaLateReply = null;
      };
    }
  };

  const slideImageCount = extractSlideImages(state.lanes, state.selectedId, state.slideIndex).length;

  // Auto-send bootstrap prompt from NewDeckDialog
  useEffect(() => {
    if (!state._bootstrap) return;
    const { prompt, images } = state._bootstrap;
    dispatch({ type: "CLEAR_BOOTSTRAP" });
    if (!prompt && images.length === 0) return;
    // Inject images into pendingImages so they're sent with the message
    if (images.length > 0) setPendingImages(images.map((dataUrl, i) => ({ dataUrl, name: `ref-${i + 1}` })));
    // Slight delay to let images state settle, then send
    setTimeout(() => {
      const msg = prompt || "Build slides from the attached images.";
      // Replicate the send flow inline (since send() reads pendingImages from state)
      const imgs = images.map((dataUrl, i) => ({ dataUrl, name: `ref-${i + 1}` }));
      setPendingImages([]);
      dispatch({ type: "ADD_MSG", role: "user", content: msg, images: imgs.map((i) => i.dataUrl) });
      dispatch({ type: "SET_LOADING", value: true });
      dispatch({ type: "ADD_MSG", role: "assistant", content: "", tools: [], _streaming: true });
      const onUpdate = (lanes, debug) => { dispatch({ type: "LOAD_LANES", lanes }); dispatch({ type: "SET_DEBUG", text: debug }); };
      const onToolCall = (evt) => { dispatch({ type: "STREAM_TOOL", event: evt }); if (evt.type === "done" && evt.jump?.length > 0) { dispatch({ type: "SELECT", id: evt.jump[0].itemId }); dispatch({ type: "SET_SLIDE_INDEX", index: evt.jump[0].slideIdx ?? 0 }); } };
      callVera(msg, state.lanes, state.selectedId, state.slideIndex, onUpdate, imgs, state.branding, state.guidelines, onToolCall, state.chatMessages).then((result) => {
        dispatch({ type: "FINALIZE_STREAM", content: result.message, jumps: result.jumps });
        if (result.jumps?.length > 0) { dispatch({ type: "SELECT", id: result.jumps[0].itemId }); dispatch({ type: "SET_SLIDE_INDEX", index: result.jumps[0].slideIdx ?? 0 }); }
        if (result.lanes) dispatch({ type: "LOAD_LANES", lanes: result.lanes });
        if (result.branding) dispatch({ type: "SET_BRANDING", branding: result.branding });
        dispatch({ type: "SET_DEBUG", text: result.debug || "" });
        dispatch({ type: "SET_LOADING", value: false });
      });
    }, 100);
  }, [state._bootstrap]);

  return (


    <div style={{ width: isMobile ? "100%" : 260, flex: isMobile ? 1 : undefined, borderLeft: isMobile ? "none" : `1px solid ${T.border}`, background: T.bgPanel, display: "flex", flexDirection: "column", flexShrink: 0 }}
      onDragOver={(e) => { e.preventDefault(); e.dataTransfer.dropEffect = "copy"; }} onDrop={handleDrop}>
      <div style={{ padding: "10px 14px", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 6 }}><span style={{ fontFamily: FONT.mono, fontSize: 13, fontWeight: 700, color: T.accent }}>VERA</span><span style={{ fontSize: 9, color: T.textDim, fontFamily: FONT.mono }}>agentic pilot 🔧</span></div>
        <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
          <button onClick={() => dispatch({ type: "RESET_CHAT" })} title="Clear chat" style={{ background: "none", border: "none", cursor: "pointer", padding: 2, fontFamily: FONT.mono, fontSize: 10, color: T.textDim, opacity: 0.5 }} onMouseEnter={(e) => e.currentTarget.style.opacity = 1} onMouseLeave={(e) => e.currentTarget.style.opacity = 0.5}>⟳</button>
          <button onClick={() => dispatch({ type: "SET_CHAT", open: false })} style={{ background: "none", border: "none", cursor: "pointer", padding: 2, display: isMobile ? "none" : "block" }}><X size={14} color={T.textDim} /></button>
        </div>
      </div>
      {state.lastDebug && <div style={{ padding: "3px 10px", background: T.amber + "12", borderBottom: `1px solid ${T.amber}30`, fontFamily: FONT.mono, fontSize: 9, color: T.amber, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", flexShrink: 0 }}>{state.lastDebug}</div>}
      <div ref={scrollRef} style={{ flex: 1, overflowY: "auto", padding: 10, display: "flex", flexDirection: "column", gap: 6 }}>
        {state.chatMessages.length === 0 && <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 12, padding: "20px 10px" }}>
          <span style={{ fontSize: 28, opacity: 0.3 }}>🤖</span>
          <span style={{ fontFamily: FONT.body, fontSize: 14, color: T.textDim, textAlign: "center", lineHeight: 1.5 }}>What would you like to create?</span>
          <div style={{ display: "flex", flexDirection: "column", gap: 6, width: "100%" }}>
            {[
              "Create a 10-slide deck about the AI agentic loop",
              "Make a pitch deck for a SaaS startup",
              "Build a training session on prompt engineering",
              "Create slides explaining how LLMs work",
              "Design an executive summary on AI trends 2026",
            ].map((prompt, i) => (
              <button key={i} onClick={() => send(prompt)}
                style={{ padding: "8px 12px", fontSize: 13, fontFamily: FONT.body, color: T.text, background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 8, cursor: "pointer", textAlign: "left", lineHeight: 1.4, transition: "border-color .15s, background .15s" }}
                onMouseEnter={(e) => { e.currentTarget.style.borderColor = T.accent; e.currentTarget.style.background = T.accent + "10"; }}
                onMouseLeave={(e) => { e.currentTarget.style.borderColor = T.border; e.currentTarget.style.background = T.bgCard; }}>
                {prompt}
              </button>
            ))}
          </div>
        </div>}
        {state.chatMessages.map((m, i) => (
          <div key={i} style={{ display: "flex", flexDirection: "column", gap: 4, alignSelf: m.role === "user" ? "flex-end" : "flex-start", maxWidth: "90%" }}>
            {/* Images */}
            {m.images?.length > 0 && <div style={{ padding: "8px 10px", borderRadius: 6, background: T.accent + "18", display: "flex", gap: 4, flexWrap: "wrap" }}>
              {m.images.map((src, j) => src.startsWith("data:") ?
                <img key={j} src={src} style={{ width: 48, height: 48, objectFit: "cover", borderRadius: 4, border: `1px solid ${T.border}` }} /> :
                <div key={j} style={{ width: 48, height: 48, borderRadius: 4, border: `1px solid ${T.border}`, background: T.bgInput, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16 }}>🖼</div>
              )}
            </div>}
            {/* User message */}
            {m.role === "user" && m.content && <div style={{ padding: "8px 10px", borderRadius: 6, fontSize: 14, lineHeight: 1.5, fontFamily: FONT.body, background: T.accent + "18", color: T.text, wordBreak: "break-word" }}>{m.content}</div>}
            {/* Tool traces (assistant streaming) */}
            {m.role === "assistant" && m.tools?.length > 0 && m.tools.map((tool, ti) => (
              <ToolTraceCard key={ti} tool={tool} dispatch={dispatch} />
            ))}
            {/* Thinking indicator */}
            {m.role === "assistant" && m._streaming && m._thinking && <div style={{ padding: "4px 10px", borderRadius: 6, fontSize: 13, fontFamily: FONT.mono, color: T.accent, display: "flex", alignItems: "center", gap: 6 }}><span style={{ animation: "spin 1s linear infinite", display: "inline-block", fontSize: 10 }}>⚡</span> thinking...</div>}
            {/* Assistant text */}
            {m.role === "assistant" && m.content && m._system && <div style={{ padding: "4px 10px", borderRadius: 6, fontSize: 10, fontFamily: FONT.mono, color: T.textDim, textAlign: "center", opacity: 0.7 }}>{m.content}</div>}
            {m.role === "assistant" && m.content && !m._system && <div style={{ padding: "8px 10px", borderRadius: 6, fontSize: 14, lineHeight: 1.5, fontFamily: FONT.body, background: T.bgCard, color: T.textMuted, wordBreak: "break-word" }}><ChatMarkdown text={m.content} /></div>}
            {/* Jump links */}
            {m.jumps?.length > 0 && <div style={{ display: "flex", gap: 4, flexWrap: "wrap", padding: "0 4px" }}>
              {m.jumps.map((j, k) => (
                <span key={k} onClick={() => { dispatch({ type: "SELECT", id: j.itemId }); dispatch({ type: "SET_SLIDE_INDEX", index: j.slideIdx }); }}
                  style={{ display: "inline-flex", alignItems: "center", gap: 3, padding: "2px 8px", borderRadius: 10, background: T.accent + "20", border: `1px solid ${T.accent}40`, cursor: "pointer", fontSize: 9, fontFamily: FONT.mono, fontWeight: 600, color: T.accent, transition: "all .15s" }}
                  onMouseEnter={(e) => { e.currentTarget.style.background = T.accent + "40"; }}
                  onMouseLeave={(e) => { e.currentTarget.style.background = T.accent + "20"; }}>
                  <span style={{ fontSize: 9 }}>▶</span> {j.title}{j.slideIdx > 0 ? ` #${j.slideIdx + 1}` : ""}
                </span>
              ))}
            </div>}
          </div>
        ))}
        {state.chatLoading && !state.chatMessages.some((m) => m._streaming) && <div style={{ padding: "8px 10px", borderRadius: 6, fontSize: 13, background: T.bgCard, color: T.accent, fontFamily: FONT.mono, alignSelf: "flex-start", display: "flex", alignItems: "center", gap: 6 }}><span style={{ animation: "spin 1s linear infinite", display: "inline-block" }}>🔧</span> working...</div>}
      </div>
      {(slideImageCount > 0 || pendingImages.length > 0) && <div style={{ padding: "4px 10px", borderTop: `1px solid ${T.border}`, display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap" }}>
        {slideImageCount > 0 && <span style={{ fontFamily: FONT.mono, fontSize: 9, color: T.accent, fontWeight: 600 }}>👁 {slideImageCount} from slide</span>}
        {pendingImages.length > 0 && <span style={{ fontFamily: FONT.mono, fontSize: 9, color: T.green, fontWeight: 600 }}>📎 {pendingImages.length} attached</span>}
      </div>}
      {pendingImages.length > 0 && <div style={{ padding: "4px 10px", display: "flex", gap: 4, flexWrap: "wrap", borderTop: `1px solid ${T.border}` }}>
        {pendingImages.map((img, i) => (
          <div key={i} style={{ position: "relative" }}>
            <img src={img.dataUrl} style={{ width: 40, height: 40, objectFit: "cover", borderRadius: 4, border: `1px solid ${T.border}` }} />
            <span onClick={() => removeImage(i)} style={{ position: "absolute", top: -4, right: -4, width: 14, height: 14, borderRadius: "50%", background: T.red, color: "#fff", fontSize: 9, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", lineHeight: 1 }}>×</span>
          </div>
        ))}
      </div>}
      <div style={{ padding: "8px 10px", borderTop: `1px solid ${T.border}`, display: "flex", gap: 6 }}>
        <textarea ref={textareaRef} value={input} onChange={(e) => setInput(e.target.value)} onPaste={handlePaste}
          onKeyDown={(e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); } }}
          placeholder={pendingImages.length > 0 ? "Describe what to do with images..." : "Tell Vera... (paste images here)"}
          rows={2} style={S.input({ padding: "6px 8px", borderRadius: 4, resize: "none", lineHeight: 1.4 })} />
        <button onClick={() => send()} disabled={state.chatLoading || (!input.trim() && pendingImages.length === 0)}
          style={{ padding: "0 12px", background: state.chatLoading || (!input.trim() && pendingImages.length === 0) ? T.border : T.accent, color: "#fff", border: "none", borderRadius: 4, cursor: state.chatLoading || (!input.trim() && pendingImages.length === 0) ? "not-allowed" : "pointer", fontSize: 14, fontWeight: 700, alignSelf: "stretch" }}>↑</button>
      </div>
    </div>
  );
}

// ━━━ JSON Clipboard Modal ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
function JsonClipboardModal({ mode, setMode, state, dispatch }) {
  const [text, setText] = useState("");
  const [copied, setCopied] = useState(false);
  const [tab, setTab] = useState(mode);
  const [error, setError] = useState(null);
  const textareaRef = useRef(null);

  // ESC to close
  useEffect(() => {
    const h = (e) => { if (e.key === "Escape") setMode(null); };
    window.addEventListener("keydown", h);
    return () => window.removeEventListener("keydown", h);
  }, []);

  // Find selected concept
  let concept = null;
  for (const l of state.lanes) { const f = l.items.find((i) => i.id === state.selectedId); if (f) { concept = f; break; } }

  // Build copy JSON
  useEffect(() => {
    setError(null);
    if (tab === "copy") {
      if (concept) {
        const data = { concepts: [{ id: concept.id, title: concept.title, slides: concept.slides }] };
        setText(JSON.stringify(data, null, 2));
      } else {
        const save = extractSave(state);
        const cleaned = { ...save, chatMessages: save.chatMessages?.map((m) => m.images ? { ...m, images: [] } : m) || [] };
        setText(JSON.stringify({ _vela: 1, data: cleaned }, null, 2));
      }
      setCopied(false);
    } else {
      setText("");
      setCopied(false);
    }
  }, [tab]);

  const handleCopy = async () => {
    try { velaClipboard(text); setCopied(true); setTimeout(() => setCopied(false), 2000); } catch {}
  };

  const handlePaste = () => {
    setError(null);
    let raw;
    try { raw = JSON.parse(text); } catch { setError("Invalid JSON — check syntax"); return; }

    if (raw.concepts && Array.isArray(raw.concepts)) {
      dispatch({ type: "IMPORT_CONCEPTS", concepts: raw.concepts });
      setMode(null);
    } else if (raw._vela && raw.data) {
      const sanitized = validateAndSanitizeDeck(raw.data);
      dispatch({ type: "LOAD", payload: sanitized });
      setMode(null);
    } else if (raw.lanes) {
      const sanitized = validateAndSanitizeDeck(raw);
      dispatch({ type: "LOAD", payload: sanitized });
      setMode(null);
    } else if (Array.isArray(raw)) {
      dispatch({ type: "IMPORT_CONCEPTS", concepts: [{ title: "Imported Slides", slides: raw }] });
      setMode(null);
    } else {
      setError("Unrecognized format. Expected: {concepts:[...]}, {lanes:[...]}, or slides array.");
    }
  };

  return (
    <div onClick={() => setMode(null)} style={{ position: "fixed", inset: 0, zIndex: 9999, background: "rgba(0,0,0,0.6)", display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: T.bgPanel, border: `1px solid ${T.border}`, borderRadius: 8, width: 560, maxWidth: "90vw", maxHeight: "80vh", display: "flex", flexDirection: "column", boxShadow: "0 16px 48px rgba(0,0,0,0.4)" }}>
        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 16px", borderBottom: `1px solid ${T.border}` }}>
          <div style={{ display: "flex", gap: 0 }}>
            {["copy", "paste"].map((t) => (
              <button key={t} onClick={() => setTab(t)} style={{
                padding: "4px 14px", fontSize: 13, fontFamily: FONT.mono, fontWeight: 700, cursor: "pointer",
                background: tab === t ? T.accent + "20" : "transparent", color: tab === t ? T.accent : T.textMuted,
                border: `1px solid ${tab === t ? T.accent : T.border}`, borderRadius: t === "copy" ? "4px 0 0 4px" : "0 4px 4px 0",
                textTransform: "uppercase", letterSpacing: "0.05em"
              }}>{t}</button>
            ))}
          </div>
          <button onClick={() => setMode(null)} style={{ background: "none", border: "none", color: T.textDim, cursor: "pointer", fontSize: 16, padding: 4 }}>✕</button>
        </div>

        {/* Info */}
        <div style={{ padding: "8px 16px", fontFamily: FONT.mono, fontSize: 10, color: T.textDim }}>
          {tab === "copy"
            ? (concept ? `Concept: "${concept.title}" · ${concept.slides.length} slides` : "Full deck state (no concept selected)")
            : "Paste JSON: {concepts: [{title, slides}]}, full deck export, or raw slides array"
          }
        </div>

        {/* Textarea */}
        <div style={{ flex: 1, padding: "0 16px", minHeight: 0 }}>
          <textarea
            ref={textareaRef}
            value={text}
            onChange={(e) => { if (tab === "paste") { setText(e.target.value); setError(null); } }}
            readOnly={tab === "copy"}
            placeholder={tab === "paste" ? '{\n  "concepts": [\n    { "title": "My Deck", "slides": [...] }\n  ]\n}' : ""}
            style={{
              width: "100%", height: 320, resize: "none", padding: 12, fontFamily: FONT.mono, fontSize: 13, lineHeight: 1.5,
              background: T.bg, color: T.text, border: `1px solid ${T.border}`, borderRadius: 6, outline: "none",
              tabSize: 2,
            }}
            onFocus={(e) => tab === "copy" && e.target.select()}
          />
        </div>

        {/* Error */}
        {error && <div style={{ padding: "4px 16px", fontFamily: FONT.mono, fontSize: 10, color: T.red, fontWeight: 600 }}>⚠ {error}</div>}

        {/* Actions */}
        <div style={{ display: "flex", justifyContent: "flex-end", gap: 8, padding: "10px 16px", borderTop: `1px solid ${T.border}` }}>
          {tab === "copy" ? (
            <button onClick={handleCopy} style={{
              padding: "6px 16px", fontSize: 13, fontFamily: FONT.mono, fontWeight: 700, cursor: "pointer",
              background: copied ? T.green : T.accent, color: "#fff", border: "none", borderRadius: 4,
            }}>{copied ? "✓ Copied!" : "Copy to clipboard"}</button>
          ) : (
            <button onClick={handlePaste} disabled={!text.trim()} style={{
              padding: "6px 16px", fontSize: 13, fontFamily: FONT.mono, fontWeight: 700, cursor: text.trim() ? "pointer" : "default",
              background: text.trim() ? T.green : T.border, color: text.trim() ? "#fff" : T.textDim, border: "none", borderRadius: 4,
            }}>Import JSON</button>
          )}
        </div>
      </div>
    </div>
  );
}


